// Build Anthropic prompt for pattern evaluation
const patterns = $input.all().map(item => item.json);

if (patterns.length === 0) {
  return [{ json: { skip: true, reason: 'No patterns to evaluate' } }];
}

const systemPrompt = `You are a GTM pattern analyst. Evaluate experiment patterns and determine which are likely to become market winners.

For each pattern, assess:
1. Is this a meaningful GTM experiment or noise?
2. What is the strategic intent behind this pattern?
3. Should PMMs consider adopting this pattern?

Respond with JSON array:
[
  {
    "pattern_id": "uuid",
    "is_meaningful": true/false,
    "strategic_intent": "string (1-2 sentences)",
    "recommendation": "adopt|monitor|ignore",
    "reasoning": "string (1-2 sentences)"
  }
]`;

const userContent = `Evaluate these experiment patterns:

${JSON.stringify(patterns, null, 2)}

Respond with JSON only.`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2000,
  temperature: 0.2,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    skip: false,
    patterns_count: patterns.length,
    patterns: patterns,
    anthropic_body: anthropicBody
  }
}];

// Parse Anthropic response
const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';

let evaluations = [];
try {
  evaluations = JSON.parse(content);
} catch (e) {
  // Try to extract JSON from response
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    evaluations = JSON.parse(jsonMatch[0]);
  }
}

return evaluations.map(e => ({ json: e }));

// Build run summary
const stats = $('Get Summary Stats').first().json;
const provenCount = $('Emit Proven Signals').first().json.proven_count || 0;
const emergingCount = $('Emit Emerging Signals').first().json.emerging_count || 0;

return [{
  json: {
    run_completed_at: new Date().toISOString(),
    total_patterns: stats.total_patterns,
    proven_patterns: stats.proven_patterns,
    emerging_patterns: stats.emerging_patterns,
    instances_this_week: stats.instances_this_week,
    proven_signals_emitted: provenCount,
    emerging_signals_emitted: emergingCount,
    total_signals_emitted: provenCount + emergingCount
  }
}];
